#include <stdlib.h>
#include <string.h>

void bad() {
    char *buf = (char *)malloc(10);
    if (buf == NULL) return;
    strcpy(buf, "hello");
    free(buf);
    /* BUG: use after free */
    buf[0] = 'X';
}

#include <stdlib.h>
#include <string.h>

void good() {
    char *buf = (char *)malloc(10);
    if (buf == NULL) return;
    strcpy(buf, "hello");
    printf("%s\n", buf);
    free(buf);
    buf = NULL;  /* safe: nulled after free */
}

#include <string.h>

char *get_data();

void bad() {
    char *data = get_data();
    /* BUG: no null check before use */
    size_t len = strlen(data);
    (void)len;
}

#include <string.h>

char *get_data();

void good() {
    char *data = get_data();
    if (data == NULL) return;  /* safe: null check */
    size_t len = strlen(data);
    (void)len;
}

#include <stdlib.h>
#include <limits.h>

void *bad(int n) {
    /* BUG: n * sizeof(int) can overflow when n is large */
    void *buf = malloc(n * sizeof(int));
    return buf;
}

#include <stdlib.h>
#include <limits.h>

void *good(int n) {
    /* Safe: check before multiplication */
    if (n <= 0 || n > INT_MAX / (int)sizeof(int)) return NULL;
    void *buf = malloc((size_t)n * sizeof(int));
    return buf;
}
